#!/usr/bin/env python3
"""Generate runtime memory model training pairs for k8s-sage.

Covers JVM, Go, Python, Node.js, .NET, Rust, and cross-runtime memory
models for Kubernetes right-sizing. Each runtime has conceptual pairs
plus 3-5 workload scenarios with realistic metrics and recommendations.

Output: ml/dataset/raw/runtime_memory_pairs.jsonl
"""

import json
from pathlib import Path

SYSTEM_PROMPT = (
    "You are k8s-sage, a Kubernetes resource efficiency specialist. "
    "Analyse the provided workload metrics and give actionable right-sizing "
    "recommendations. Be specific about numbers, explain your reasoning, "
    "and flag risks."
)

OUTPUT_PATH = Path(__file__).parent / "raw" / "runtime_memory_pairs.jsonl"


def make_pair(
    id_str: str, user: str, assistant: str, category: str,
    provenance: str, **extra_meta
) -> dict:
    """Create a validated training pair."""
    assert len(assistant) >= 50, f"{id_str}: assistant too short ({len(assistant)} chars)"
    assert category in ("right-sizing", "classification", "runtime-specific", "edge-case")
    meta = {"category": category, "provenance": provenance}
    meta.update(extra_meta)
    return {
        "id": id_str,
        "source": "synthetic",
        "system": SYSTEM_PROMPT,
        "user": user,
        "assistant": assistant,
        "metadata": meta,
    }


# ── JVM Memory Model ────────────────────────────────────────────────


def jvm_memory_pairs() -> list[dict]:
    """JVM GC, heap, off-heap, metaspace, container awareness."""
    p = "Expert knowledge: JVM memory model and container interactions"
    pairs = []

    pairs.append(make_pair("runtime-mem-jvm-001",
        "How does G1GC memory usage look inside a Kubernetes container and how should I set requests/limits?",
        "## G1GC Memory Model in Containers\n\n**G1GC divides the heap into regions** (typically 1-32MB each). Total JVM memory is:\n\n1. **Java Heap** (-Xmx): The main managed area. G1GC targets ~45% occupancy after full GC by default.\n2. **Metaspace**: Class metadata, loaded at startup. Typically 100-300Mi for a Spring Boot app. Set `-XX:MaxMetaspaceSize=256m` to cap.\n3. **Thread stacks**: Default 1MB per thread. 200 threads = 200Mi.\n4. **Code cache**: JIT compiled code. 50-250Mi depending on application size.\n5. **Direct/NIO buffers**: Off-heap allocations via ByteBuffer.allocateDirect(). Common in Netty-based apps.\n6. **GC overhead**: G1GC needs ~10-15% of heap for remembered sets and other tracking structures.\n\n**Container memory formula:**\n```\ncontainer_limit = Xmx + metaspace + (thread_count * 1Mi) + code_cache + direct_buffers + GC_overhead + 256Mi_safety\n```\n\n**Example**: -Xmx=4Gi, 200 threads, Spring Boot\n- Heap: 4Gi\n- Metaspace: 256Mi\n- Threads: 200Mi\n- Code cache: 128Mi\n- GC overhead: 600Mi (15% of heap)\n- Direct buffers: 128Mi (Netty default)\n- Safety: 256Mi\n- **Total: ~5.5Gi container limit**\n\n**Common mistake**: Setting container limit = Xmx. The JVM WILL get OOMKilled because off-heap memory exceeds the gap.\n\n**Recommendations:**\n- Request: Set to steady-state RSS (P95 of working set)\n- Limit: Xmx * 1.5 as a starting point, tune down after observing actual RSS\n- Always set `-XX:+UseContainerSupport` (default since JDK 10)\n- Set `-XX:MaxRAMPercentage=75` instead of -Xmx to let JVM auto-size to container limit",
        "runtime-specific", p, runtime="jvm"))

    pairs.append(make_pair("runtime-mem-jvm-002",
        "What is the difference between G1GC, ZGC, and Shenandoah for Kubernetes workloads and which should I choose?",
        "## GC Algorithm Selection for K8s Workloads\n\n**G1GC (default since JDK 9):**\n- Pause target: 200ms default, tunable via `-XX:MaxGCPauseMillis`\n- Heap overhead: ~10-15% for remembered sets\n- Best for: General purpose, 4-16Gi heaps\n- K8s impact: Predictable memory, moderate CPU spikes during GC\n\n**ZGC (production since JDK 15):**\n- Pause target: <1ms regardless of heap size\n- Heap overhead: ~3-5% less than G1 (colored pointers, no remembered sets)\n- Memory overhead: Requires 2x virtual address space mapping (not physical RSS)\n- Best for: Latency-sensitive services, large heaps (16Gi+)\n- K8s impact: Smoother CPU usage, but `container_memory_rss` may show higher due to multi-mapping. Do NOT alert on virtual memory with ZGC.\n\n**Shenandoah:**\n- Pause target: <10ms, concurrent compaction\n- Heap overhead: Similar to G1 (~10%)\n- Best for: Moderate latency requirements, RedHat/OpenJDK environments\n- K8s impact: Higher CPU baseline due to concurrent collection\n\n**Right-sizing impact:**\n\n| GC | Memory overhead | CPU overhead | Recommendation style |\n|----|----------------|-------------|---------------------|\n| G1GC | +15% heap | Spiky (GC pauses) | Size CPU for P99 spikes |\n| ZGC | +5% heap, 2x virtual | Steady, higher baseline | Size CPU for P95 |\n| Shenandoah | +10% heap | Steady, moderate | Size CPU for P95 |\n\n**For K8s right-sizing**: ZGC produces the smoothest metrics (easier to right-size) but needs careful memory limit calculation since `memory.current` in cgroups includes the multi-mapped pages. G1GC is the safe default when you're unsure.",
        "runtime-specific", p, runtime="jvm"))

    pairs.append(make_pair("runtime-mem-jvm-003",
        "My JVM workload shows memory usage climbing linearly until OOMKill. What's happening and how do I right-size?",
        "## JVM Memory Leak vs Normal Behaviour\n\n**Linear memory growth until OOMKill has several causes:**\n\n1. **Native memory leak** (most common in containers):\n   - Java heap is fine (GC reclaims), but native allocations grow unbounded\n   - Common culprits: Netty direct buffers not released, JNI allocations, gzip streams not closed\n   - Diagnosis: `-XX:NativeMemoryTracking=summary` then `jcmd <pid> VM.native_memory summary`\n\n2. **Metaspace leak**:\n   - Dynamic class loading (e.g., Groovy scripts, CGLIB proxies, reflection) creates classes that never unload\n   - Without `-XX:MaxMetaspaceSize`, metaspace grows until container OOM\n   - Fix: Set `-XX:MaxMetaspaceSize=256m` and fix the class loader leak\n\n3. **Thread leak**:\n   - Each thread allocates ~1MB stack. Leaked threads accumulate memory.\n   - `jcmd <pid> Thread.print` shows thread count. Compare with expected.\n\n4. **Heap correctly sized but container limit too tight**:\n   - JVM heap has sawtooth pattern (fills, GC reclaims). Peak of sawtooth + off-heap > container limit.\n   - Fix: Increase container limit to Xmx * 1.5+\n\n**Right-sizing approach for leaky JVMs:**\n- Short-term: Set memory limit to handle 48h of growth + headroom. Rely on pod restart to reclaim.\n- Long-term: Fix the leak. Use `-XX:NativeMemoryTracking=detail` to identify the leak category.\n- Container memory request: Based on P50 usage (the \"just after restart\" baseline)\n- Container memory limit: Based on Max observed before OOM, plus 20% headroom\n\n**Safety rule**: If a JVM workload restarts more than once per 7d due to OOM, do NOT reduce memory. Investigate the root cause first.",
        "runtime-specific", p, runtime="jvm"))

    pairs.append(make_pair("runtime-mem-jvm-004",
        "Workload: deployment/order-service\nReplicas: 4\nContainer: eclipse-temurin:21-jre\nCPU Request: 2000m, Limit: 4000m\nMemory Request: 4Gi, Limit: 4Gi\nCPU Usage (7d): P50=350m, P95=800m, P99=1200m, Max=2000m\nMemory Usage (7d): P50=3.2Gi, P95=3.5Gi, P99=3.7Gi, Max=3.9Gi\nJVM Flags: -Xmx3g -Xms3g -XX:+UseG1GC -XX:+UseContainerSupport\nPattern: Steady\nRestarts (7d): 0",
        "## Analysis\n\n**Memory**: JVM heap is set to 3Gi (-Xmx3g = -Xms3g, so heap is pre-allocated). Total expected:\n- Heap: 3Gi (pre-allocated, constant)\n- Metaspace: ~200Mi (typical for a service)\n- Thread stacks: ~150Mi (150 threads estimate)\n- GC overhead: ~450Mi (15% of heap for G1)\n- Code cache + buffers: ~150Mi\n- Total steady-state: ~3.95Gi\n\nP50=3.2Gi to Max=3.9Gi confirms this model. The 700Mi range is GC sawtooth on the heap.\n\n**Critical concern**: Max=3.9Gi against limit=4Gi leaves only 100Mi headroom. One burst of direct buffer allocation or a metaspace expansion triggers OOMKill.\n\n**CPU**: Steady pattern with reasonable P95/P50 ratio of 2.3x. Classic request-driven JVM workload.\n\n## Recommendations\n\n**Memory**: Request=4Gi (keep). Limit=5Gi (increase from 4Gi).\n- This is a LIMIT INCREASE, not a reduction. Current limit is dangerously tight.\n- With Xmx=3Gi, container needs minimum 3Gi * 1.5 = 4.5Gi, ideally 5Gi.\n- Confidence: 0.95\n- Risk: LOW -- increasing limits prevents OOMKill\n\n**CPU**: Request=960m (P95 * 1.20). Limit=2500m (Max * 1.25).\n- Savings: 1040m request per pod = 4160m total across 4 replicas\n- Confidence: 0.90\n- Risk: LOW -- steady pattern, 7d data, no restarts\n\n**JVM-specific**: Consider `-XX:MaxRAMPercentage=70` instead of explicit Xmx. With 5Gi limit, heap auto-sizes to ~3.5Gi, leaving room for off-heap.",
        "right-sizing", p, runtime="jvm", pattern="steady"))

    pairs.append(make_pair("runtime-mem-jvm-005",
        "Workload: deployment/analytics-engine\nReplicas: 2\nContainer: eclipse-temurin:17-jre\nCPU Request: 8000m, Limit: 8000m\nMemory Request: 32Gi, Limit: 32Gi\nCPU Usage (7d): P50=500m, P95=6000m, P99=7500m, Max=8000m\nMemory Usage (7d): P50=18Gi, P95=25Gi, P99=28Gi, Max=30Gi\nJVM Flags: -Xmx24g -Xms8g -XX:+UseZGC\nPattern: Batch\nRestarts (7d): 0",
        "## Analysis\n\n**Memory**: ZGC with -Xms8g/-Xmx24g. The wide range (8-24Gi) means heap grows on demand:\n- Idle: ~8Gi heap + 4Gi off-heap = ~12Gi (below P50=18Gi, so analytics runs frequently)\n- Active analytics: Heap expands toward 24Gi as data is processed\n- P50=18Gi: Mid-processing steady state\n- Max=30Gi: Full heap (24Gi) + off-heap (6Gi)\n\n**ZGC note**: ZGC uses colored pointers which double-map heap pages. `container_memory_rss` may report higher than actual physical usage. Check `container_memory_working_set_bytes` instead for accurate accounting.\n\n**CPU**: Classic batch pattern. P50=500m (idle/light queries) to Max=8000m (full analytical processing). Guaranteed QoS is correct for batch -- needs full CPU during processing.\n\n## Recommendations\n\n**CPU**: Keep at 8000m request = limit. Max=8000m means the workload uses 100% of available CPU during batch runs. Any reduction delays batch completion.\n- No savings on CPU.\n\n**Memory**: Request=24Gi (reduce from 32Gi). Limit=32Gi (keep).\n- P95=25Gi * 1.20 = 30Gi for request seems high. But ZGC needs room to grow. P50-based request = 21.6Gi rounds to 24Gi.\n- Savings: 8Gi request per pod = 16Gi total (scheduler-visible savings)\n- Confidence: 0.75\n- Risk: MEDIUM -- batch memory depends on dataset size. Monitor for new datasets.\n\n**Optimization**: If analytics runs are scheduled (not continuous), consider:\n1. KEDA ScaledJob instead of Deployment -- scale to zero between runs\n2. With -Xms=8Gi and ZGC, JVM releases memory back to OS. Pair with `memory.high` (cgroups v2) instead of hard limit for better node utilization.",
        "right-sizing", p, runtime="jvm", pattern="batch"))

    pairs.append(make_pair("runtime-mem-jvm-006",
        "How does -XX:+UseContainerSupport affect JVM right-sizing in Kubernetes?",
        "## UseContainerSupport and JVM Container Awareness\n\n**Since JDK 10 (backported to 8u191), the JVM reads cgroup limits** instead of host memory. This is critical for K8s.\n\n**What UseContainerSupport does:**\n1. `Runtime.getRuntime().maxMemory()` returns container limit, not node memory\n2. `-XX:MaxRAMPercentage=75.0` calculates heap as 75% of container limit\n3. GC ergonomics (thread count, region size) scale to container, not node\n4. Without it on a 64Gi node with 4Gi container limit, JVM sees 64Gi and may set heap to 16Gi → instant OOMKill\n\n**Enabled by default since JDK 10**, but verify with:\n```bash\njava -XX:+PrintFlagsFinal -version 2>&1 | grep UseContainerSupport\n```\n\n**Right-sizing implications:**\n\n| Flag combination | Heap size (4Gi container) | Safe? |\n|-----------------|--------------------------|-------|\n| -Xmx3g | 3Gi fixed | Yes, if limit > Xmx * 1.3 |\n| -XX:MaxRAMPercentage=75 | 3Gi (75% of 4Gi) | Yes, dynamic |\n| -XX:MaxRAMPercentage=75 + no container support | 48Gi (75% of 64Gi node) | OOMKill |\n| No flags + container support | ~25% of limit = 1Gi | Under-utilized |\n\n**Best practice for K8s:**\n1. Use `-XX:MaxRAMPercentage=70` (not explicit -Xmx). Heap auto-adjusts when you change container limits.\n2. Set `-XX:InitialRAMPercentage=50` for faster startup (pre-allocate 50% of calculated max).\n3. Container memory request = expected steady-state RSS\n4. Container memory limit = the value MaxRAMPercentage calculates against\n\n**Pitfall**: cgroups v1 vs v2. On cgroups v1, JVM reads `/sys/fs/cgroup/memory/memory.limit_in_bytes`. On v2, it reads `/sys/fs/cgroup/memory.max`. JDK 15+ handles both. Older JDKs may not detect v2 correctly.",
        "runtime-specific", p, runtime="jvm"))

    pairs.append(make_pair("runtime-mem-jvm-007",
        "How do off-heap and direct ByteBuffers affect JVM container memory and right-sizing?",
        "## Off-Heap Memory in JVM Containers\n\n**Off-heap memory is invisible to `-Xmx` but counts toward container cgroup limit.** This is the #1 cause of unexpected JVM OOMKills in K8s.\n\n**Sources of off-heap memory:**\n\n1. **Direct ByteBuffers** (`ByteBuffer.allocateDirect()`):\n   - Used by Netty, gRPC, Kafka clients, NIO channels\n   - Default max: `-XX:MaxDirectMemorySize` = Xmx if not set\n   - A Netty-based service can easily use 500Mi-2Gi of direct memory\n\n2. **Memory-mapped files** (`MappedByteBuffer`):\n   - Used by Kafka (log segments), RocksDB (LSM tree), Lucene (index segments)\n   - Shows in RSS but may be shared/reclaimable. K8s counts it in container_memory_rss.\n\n3. **JNI allocations**:\n   - Native libraries (OpenSSL, zlib, snappy) allocate outside JVM tracking\n   - Not limited by any JVM flag\n\n4. **Thread stacks** (as covered): 1MB * thread count\n\n**How to monitor:**\n```bash\n# Inside container\njcmd 1 VM.native_memory summary\n# Shows: Heap, Thread, Class, Code, GC, Internal, Symbol, NMT, Arena, Other\n```\n\n**Right-sizing formula for off-heap-heavy workloads:**\n```\ncontainer_limit = Xmx + MaxDirectMemorySize + MaxMetaspaceSize + (threads * 1Mi) + 512Mi\n```\n\n**Example**: Netty-based API gateway\n- Xmx=2Gi, MaxDirectMemorySize=1Gi, 300 threads, heavy NIO\n- Container limit: 2Gi + 1Gi + 256Mi + 300Mi + 512Mi = ~4Gi\n- Container request: Based on observed P95 RSS (~3.2Gi)\n\n**Safety**: Always set `-XX:MaxDirectMemorySize` explicitly. Without it, the JVM allows direct allocations up to Xmx, doubling effective memory usage.",
        "runtime-specific", p, runtime="jvm"))

    # JVM scenario pairs
    pairs.append(make_pair("runtime-mem-jvm-008",
        "Workload: deployment/spring-gateway\nReplicas: 3\nContainer: eclipse-temurin:21-jre\nCPU Request: 1000m, Limit: 2000m\nMemory Request: 2Gi, Limit: 2Gi\nCPU Usage (7d): P50=150m, P95=400m, P99=600m, Max=900m\nMemory Usage (7d): P50=1.6Gi, P95=1.8Gi, P99=1.9Gi, Max=2.0Gi\nJVM Flags: -Xmx1536m -XX:+UseG1GC\nReactive framework: Spring WebFlux + Netty\nPattern: Steady\nRestarts (7d): 2 (OOMKilled)",
        "## Analysis\n\n**Memory**: OOMKills confirm the limit is too tight.\n- Heap: 1.5Gi (-Xmx1536m)\n- Netty direct buffers: 256-512Mi (WebFlux uses Netty extensively for non-blocking I/O)\n- Metaspace: ~200Mi (Spring Boot has heavy class loading)\n- Thread stacks: ~64Mi (WebFlux uses few threads, ~64 event loop threads)\n- GC overhead: ~225Mi (15% of heap)\n- Total: ~2.2-2.5Gi minimum, but container limit is 2Gi\n\nThe 2 OOMKills occur when direct buffer allocation peaks coincide with GC cycle (heap is temporarily at max + direct buffers exceed remaining room).\n\n**CPU**: Low utilization. WebFlux is non-blocking, so CPU efficiency is high. P95=400m is typical for a gateway proxying requests.\n\n## Recommendations\n\n**Memory**: Request=2.5Gi. Limit=3Gi. This is an INCREASE.\n- Heap 1.5Gi * 2 = 3Gi is the minimum safe container limit for this JVM config\n- Confidence: 0.95\n- Risk: NONE -- this fixes OOMKills\n\n**CPU**: Request=480m (P95 * 1.20). Limit=1125m (Max * 1.25).\n- Savings: 520m request per pod = 1560m total\n- Confidence: 0.90\n\n**Immediate fix**: Add `-XX:MaxDirectMemorySize=256m` to cap Netty buffers. With WebFlux, 256Mi direct memory is sufficient for most traffic patterns. This prevents unbounded direct buffer growth.\n\n**Alternative**: Switch to `-XX:MaxRAMPercentage=60` with 3Gi limit. Heap = 1.8Gi, leaving 1.2Gi for off-heap. More balanced than explicit -Xmx.",
        "right-sizing", p, runtime="jvm", pattern="steady"))

    pairs.append(make_pair("runtime-mem-jvm-009",
        "How does Metaspace work in containers and when does it cause OOMKills?",
        "## Metaspace in JVM Containers\n\n**Metaspace stores class metadata** (class definitions, method metadata, constant pools). Replaced PermGen in JDK 8.\n\n**Key characteristics:**\n- Allocated from native memory (NOT Java heap)\n- Default: no limit (grows until container OOM)\n- Grows when: new classes are loaded (reflection, CGLIB proxies, dynamic languages like Groovy/Kotlin scripts)\n- Shrinks when: class loaders are garbage collected (rare in long-running services)\n\n**Typical sizes by application type:**\n\n| Application | Metaspace |\n|------------|----------|\n| Minimal microservice | 50-80Mi |\n| Spring Boot REST API | 150-250Mi |\n| Spring Boot + JPA + many entities | 250-400Mi |\n| Application server (Tomcat/Jetty) | 200-350Mi |\n| Groovy/dynamic language heavy | 300Mi+ (grows!) |\n\n**When it causes K8s OOMKills:**\n1. No `-XX:MaxMetaspaceSize` set\n2. Application uses dynamic class loading (Groovy scripts, runtime proxies)\n3. Metaspace grows 10-50Mi per hour\n4. After days, metaspace + heap + other off-heap exceeds container limit\n5. Kernel OOMKills the JVM (not a Java OutOfMemoryError: Metaspace)\n\n**Detection**: If `container_memory_rss` grows linearly but `jvm_memory_bytes_used{area=\"heap\"}` is stable, the leak is in native/metaspace.\n\n**Fix:**\n1. Always set `-XX:MaxMetaspaceSize=256m` (or appropriate for your app)\n2. With the cap, JVM throws `java.lang.OutOfMemoryError: Metaspace` when exceeded — a Java error you can catch and handle, vs a hard OOMKill\n3. Monitor `jvm_classes_loaded_classes` — steady growth indicates a class loader leak\n\n**Right-sizing**: Include metaspace in your container memory budget. Add `-XX:MaxMetaspaceSize` to your JVM flags and account for it: `container_limit >= Xmx + MaxMetaspaceSize + thread_stacks + 512Mi`",
        "runtime-specific", p, runtime="jvm"))

    return pairs


# ── Go Memory Model ─────────────────────────────────────────────────


def go_memory_pairs() -> list[dict]:
    """Go GC, GOGC, GOMEMLIMIT, goroutine stacks, automaxprocs."""
    p = "Expert knowledge: Go runtime memory model and container interactions"
    pairs = []

    pairs.append(make_pair("runtime-mem-go-001",
        "How does Go's garbage collector affect memory usage in Kubernetes containers?",
        "## Go GC and Container Memory\n\n**Go uses a concurrent, tri-color mark-and-sweep GC.** Key behaviour for K8s:\n\n1. **GOGC (default 100)**: GC triggers when heap grows to 2x the live set. With 500Mi live data, GC runs at ~1Gi, reclaims to ~500Mi, then heap grows again.\n   - Memory overhead: ~2x live set at GOGC=100\n   - CPU overhead: ~25% of total CPU during GC cycles\n\n2. **Memory never returns to OS eagerly**: Go's runtime retains freed pages as \"idle\" spans. RSS stays high even after GC.\n   - Since Go 1.16: `madvise(MADV_FREE)` marks pages as reclaimable. Kernel reclaims under memory pressure.\n   - In K8s: `container_memory_rss` stays high but `container_memory_working_set_bytes` reflects actual need.\n\n3. **Goroutine stacks**: Each goroutine starts with 2KB stack, grows to 1MB max. 10,000 goroutines at 8KB average = 80Mi.\n   - Goroutine leak = memory leak that GC can't fix.\n\n**Right-sizing Go workloads:**\n- Use `container_memory_working_set_bytes` (not RSS) for percentile calculations\n- Memory request: Working set P95 * 1.20\n- Memory limit: RSS Max * 1.25 (RSS includes reclaimable pages the kernel needs)\n- If RSS is 2x working set, that's normal Go behaviour, not a leak\n\n**Common mistake**: Seeing RSS=2Gi, working_set=800Mi, setting limit to 1Gi → works until kernel can't reclaim fast enough under pressure → OOMKill.",
        "runtime-specific", p, runtime="go"))

    pairs.append(make_pair("runtime-mem-go-002",
        "How should I use GOMEMLIMIT for right-sizing Go workloads in Kubernetes?",
        "## GOMEMLIMIT (Go 1.19+) for K8s Right-Sizing\n\n**GOMEMLIMIT sets a soft memory target for the Go runtime.** The GC becomes more aggressive as memory approaches this limit.\n\n**Without GOMEMLIMIT (traditional):**\n- GC triggers at GOGC% growth (default: 100% = 2x live set)\n- If live set is 500Mi, Go happily uses 1Gi before GC runs\n- Container might OOMKill if limit is 800Mi\n\n**With GOMEMLIMIT:**\n- GC runs more frequently as heap approaches the limit\n- Trades CPU (more GC cycles) for memory stability\n- Prevents OOMKills from GC not running soon enough\n\n**Setting it in K8s:**\n```yaml\nenv:\n- name: GOMEMLIMIT\n  valueFrom:\n    resourceFieldRef:\n      resource: limits.memory  # Auto-tracks container limit\n```\nBut do NOT set GOMEMLIMIT = container limit. Leave headroom:\n- GOMEMLIMIT = container_limit * 0.90 (for goroutine stacks, cgo, kernel overhead)\n- Or: GOMEMLIMIT = container_limit - 100Mi (for smaller containers)\n\n**Right-sizing with GOMEMLIMIT:**\n1. Set container memory limit based on desired max RSS\n2. Set GOMEMLIMIT to 90% of limit\n3. Set GOGC=100 (or lower if CPU is cheap)\n4. Memory request = observed working set P95 * 1.20\n5. Memory limit = GOMEMLIMIT / 0.90\n\n**Example**: Go API server, live set ~400Mi\n- GOMEMLIMIT=900Mi, container limit=1Gi\n- GC runs frequently between 400Mi-900Mi, never exceeds 1Gi\n- Request: 600Mi (P95 working set), Limit: 1Gi\n\n**When NOT to use GOMEMLIMIT:**\n- CGo-heavy workloads (C allocations bypass Go GC)\n- Memory-mapped files (counted in RSS but not Go heap)\n- GOMEMLIMIT only controls Go heap, not total process memory",
        "runtime-specific", p, runtime="go"))

    pairs.append(make_pair("runtime-mem-go-003",
        "How does automaxprocs affect CPU right-sizing for Go workloads in Kubernetes?",
        "## automaxprocs and Go CPU Right-Sizing\n\n**Problem**: Go's `GOMAXPROCS` defaults to the number of host CPU cores, not the container's CPU limit.\n\nOn a 64-core node with a 500m CPU limit:\n- `GOMAXPROCS=64` by default\n- 64 OS threads compete for 500m of CPU time\n- Excessive context switching, cache thrashing, scheduler overhead\n- CPU usage appears higher than necessary\n\n**Solution**: `go.uber.org/automaxprocs` reads the cgroup CPU limit and sets GOMAXPROCS accordingly.\n\n```go\nimport _ \"go.uber.org/automaxprocs\"\n// With 500m limit: GOMAXPROCS=1\n// With 2000m limit: GOMAXPROCS=2\n// With 4000m limit: GOMAXPROCS=4\n```\n\n**Right-sizing impact:**\n\n| GOMAXPROCS | 500m limit | CPU P95 | Behaviour |\n|-----------|-----------|---------|----------|\n| 64 (default) | 500m | 480m | Thrashing, all 64 threads scheduled |\n| 1 (automaxprocs) | 500m | 350m | Efficient, single thread |\n| Savings | | 130m (27%) | Less overhead |\n\n**Best practices:**\n1. Always use automaxprocs for Go services in K8s\n2. If not using automaxprocs, set `GOMAXPROCS` env var explicitly: `ceil(cpu_limit_millicores / 1000)`\n3. For CPU limit < 1000m, GOMAXPROCS=1 is correct (Go is efficient with 1 thread for I/O-bound work)\n4. For CPU-bound Go workloads (compression, crypto, ML inference), set GOMAXPROCS = cpu_limit rounded up\n\n**Right-sizing after automaxprocs adoption:**\n- Re-measure CPU usage. P95 typically drops 15-30%\n- New CPU request = new P95 * 1.20\n- The savings from automaxprocs are real, not measurement artifacts",
        "runtime-specific", p, runtime="go"))

    pairs.append(make_pair("runtime-mem-go-004",
        "Workload: deployment/api-gateway\nRuntime: Go 1.22\nReplicas: 6\nCPU Request: 2000m, Limit: 4000m\nMemory Request: 4Gi, Limit: 8Gi\nCPU Usage (7d): P50=200m, P95=800m, P99=1200m, Max=2000m\nMemory RSS (7d): P50=2.5Gi, P95=3.0Gi, P99=3.2Gi, Max=3.5Gi\nMemory Working Set (7d): P50=800Mi, P95=1.2Gi, P99=1.5Gi, Max=1.8Gi\nGOGC=100, no GOMEMLIMIT, no automaxprocs\nGoroutine count (avg): 5000\nPattern: Steady\nRestarts (7d): 0",
        "## Analysis\n\n**Memory**: RSS (3.5Gi max) vs Working Set (1.8Gi max) — the 1.7Gi gap is reclaimable Go heap pages. This is normal Go behaviour.\n\n**Working set breakdown:**\n- Live heap: ~600Mi (GOGC=100, so GC triggers at ~1.2Gi)\n- Goroutine stacks: 5000 * ~8KB = 40Mi\n- Runtime overhead: ~100Mi\n- Total working: ~740Mi (matches P50=800Mi)\n\n**The memory limit of 8Gi is extremely wasteful.** Working set max is 1.8Gi, meaning 6.2Gi of memory limit is never used.\n\n**CPU**: No automaxprocs. On a typical 16+ core node, GOMAXPROCS=16+, causing unnecessary overhead for a workload that peaks at 2000m.\n\n## Recommendations\n\n**Memory**: Request=1.8Gi (working set P95 * 1.20 = 1.44Gi, round to 1.8Gi for Go RSS overhead). Limit=3Gi (working set Max * 1.20 + RSS headroom).\n- Savings: 2.2Gi request + 5Gi limit per pod = 13.2Gi + 30Gi across 6 replicas\n- Confidence: 0.90\n- Risk: LOW -- use working set metrics, not RSS\n\n**CPU**: Request=960m (P95 * 1.20). Limit=2500m (Max * 1.25).\n- Savings: 1040m request per pod = 6240m total\n- Confidence: 0.85\n\n**Optimizations to apply first:**\n1. Add `go.uber.org/automaxprocs` — expect 15-25% CPU reduction\n2. Set `GOMEMLIMIT=2700Mi` (90% of 3Gi limit) — GC will be more aggressive, working set stays under limit\n3. After both changes, re-measure for 7d, then right-size again. CPU request may drop to 700m.",
        "right-sizing", p, runtime="go", pattern="steady"))

    pairs.append(make_pair("runtime-mem-go-005",
        "What is Go memory ballast and should I use it in Kubernetes?",
        "## Go Memory Ballast\n\n**Ballast is a pre-allocated, never-used byte slice** that inflates the live set, making GOGC trigger less often.\n\n```go\nfunc main() {\n    ballast := make([]byte, 1<<30) // 1Gi ballast\n    _ = ballast\n    // ...\n}\n```\n\n**How it works with GOGC=100:**\n- Without ballast: 50Mi live set → GC at 100Mi → frequent GC\n- With 1Gi ballast: 1.05Gi \"live\" set → GC at 2.1Gi → rare GC, lower CPU\n\n**K8s implications:**\n- RSS immediately jumps by ballast size (but pages are never touched, so working_set stays low)\n- Container memory metrics look inflated\n- Scheduler sees higher memory request needed\n\n**Should you use it in K8s? NO, use GOMEMLIMIT instead.**\n\nBallast was a hack before Go 1.19. GOMEMLIMIT achieves the same goal (less frequent GC) without wasting address space:\n\n| Approach | Memory usage | CPU overhead | Complexity |\n|----------|-------------|-------------|------------|\n| GOGC=100, no ballast | 2x live set | Moderate GC | Simple |\n| 1Gi ballast + GOGC=100 | 1Gi + live set | Low GC | Hack |\n| GOMEMLIMIT=900Mi | Up to 900Mi | Adaptive GC | Clean |\n\n**Migration**: Remove ballast, set `GOMEMLIMIT` to container limit * 0.90. You get the same CPU savings without inflated RSS.\n\n**If you see ballast in existing workloads**: The memory request should be based on working_set, not RSS. The ballast inflates RSS but not actual memory need.",
        "runtime-specific", p, runtime="go"))

    return pairs


# ── Python Memory Model ─────────────────────────────────────────────


def python_memory_pairs() -> list[dict]:
    """Python pymalloc, GIL, multiprocessing, Celery."""
    p = "Expert knowledge: Python runtime memory model and container interactions"
    pairs = []

    pairs.append(make_pair("runtime-mem-python-001",
        "How does Python's memory allocator affect container right-sizing?",
        "## Python Memory Allocator (pymalloc) in Containers\n\n**Python uses a custom memory allocator (pymalloc) that rarely returns memory to the OS.** This is the biggest surprise for K8s operators.\n\n**How pymalloc works:**\n1. Python requests memory from OS in 256KB arenas\n2. Arenas are subdivided into pools (4KB) and blocks (8-512 bytes)\n3. When objects are freed, blocks are marked available but arenas are NOT released\n4. An arena is only released when ALL blocks in it are free (fragmentation prevents this)\n\n**K8s impact:**\n- RSS grows monotonically (ratchets up, never comes down)\n- A spike that uses 2Gi → after processing, RSS stays at 2Gi even though live objects are 500Mi\n- `container_memory_rss` shows the peak, not the current need\n- `container_memory_working_set_bytes` may also stay high due to page cache\n\n**Right-sizing Python:**\n- Memory request: Based on P95 of steady-state (exclude startup spikes if possible)\n- Memory limit: Based on Max observed + 20% headroom\n- Accept that RSS > actual need is normal for Python\n- A Python service that \"leaks\" 10-50Mi/day may just be fragmentation, not a bug\n\n**Mitigations:**\n1. `PYTHONMALLOC=malloc` — use system malloc (glibc) instead. Releases memory via `madvise`. 5-10% slower but RSS tracks actual usage.\n2. `MALLOC_TRIM_THRESHOLD_` (glibc) — tune when glibc returns memory to OS\n3. For heavy workloads: Use `multiprocessing` with max_tasks_per_child to periodically restart worker processes (releases all memory)\n4. For Celery: `--max-tasks-per-child=1000` — restart worker after 1000 tasks\n\n**Rule**: If a Python container's RSS grows 20%+ over 7d without corresponding workload increase, it's likely fragmentation. Set limit to accommodate the growth pattern and rely on periodic pod restarts (rolling restart weekly) to reclaim.",
        "runtime-specific", p, runtime="python"))

    pairs.append(make_pair("runtime-mem-python-002",
        "How does the GIL affect CPU right-sizing for Python workloads in Kubernetes?",
        "## GIL and Python CPU Right-Sizing\n\n**The Global Interpreter Lock (GIL) means a single Python process can only use ~1 CPU core** for Python bytecode execution, regardless of thread count.\n\n**K8s implications:**\n\n| Workload type | Effective CPU limit | Right-sizing approach |\n|--------------|--------------------|-----------------------|\n| Single-threaded Python | 1000m max | Request ≤ 1000m, limit = 1000m |\n| Threading (I/O-bound) | 1000m Python + N cores for I/O | Threads help for network/disk wait |\n| NumPy/Pandas (C extensions) | N cores (releases GIL) | Size like a native app |\n| multiprocessing | N cores (N processes) | Each process = 1 core, multiply |\n\n**Common mistake**: Setting CPU limit to 4000m for a single-process Flask app. The app physically cannot use more than ~1000m for Python code. The extra 3000m is wasted.\n\n**Exception**: Libraries that release the GIL:\n- NumPy/SciPy: Matrix operations run in C, use all cores\n- Pillow: Image processing releases GIL\n- hashlib: Hashing releases GIL\n- I/O operations: Network and disk release GIL\n\n**Gunicorn/uWSGI pattern:**\n- `gunicorn --workers 4` = 4 separate processes, each with its own GIL\n- CPU limit should be ≥ worker_count * expected_per_worker_cpu\n- Memory limit = worker_count * per_worker_memory (no sharing between processes)\n- Typical: `workers = 2 * cpu_limit_cores + 1`\n\n**Right-sizing rule for Python:**\n1. Check process model: single process, threading, or multiprocessing\n2. If single process: CPU request ≤ 1000m, period\n3. If multiprocessing: CPU request = worker_count * per_worker_P95\n4. Memory = worker_count * per_worker_memory (NOT shared)\n5. For Celery: each worker is a process. `--concurrency 4` = 4 processes",
        "runtime-specific", p, runtime="python"))

    pairs.append(make_pair("runtime-mem-python-003",
        "How should I right-size Python Celery workers in Kubernetes?",
        "## Celery Worker Right-Sizing in K8s\n\n**Celery workers are multiprocessing-based.** Each worker process has its own memory space and GIL.\n\n**Memory model:**\n```\ntotal_memory = master_process + (concurrency * per_task_memory)\n```\n- Master process (beat/scheduler): 100-200Mi\n- Per-worker process: 150-500Mi base + task-dependent\n- With `--concurrency 4`: 4 worker processes\n- Each process loads the full application code (no sharing due to fork-after-import)\n\n**CPU model:**\n- Each worker process can use 1 core (GIL)\n- CPU request = concurrency * expected_utilization\n- Typical: concurrency=4, each worker 60% busy → CPU request = 2400m\n\n**K8s configuration:**\n```yaml\nresources:\n  requests:\n    cpu: \"2000m\"      # concurrency(4) * 500m avg utilization\n    memory: \"2Gi\"      # 200Mi master + 4 * 400Mi workers\n  limits:\n    cpu: \"4000m\"       # concurrency(4) * 1000m max per worker\n    memory: \"3Gi\"      # peak: some tasks use more memory\n```\n\n**Critical settings:**\n1. `--max-tasks-per-child 1000`: Restart worker after 1000 tasks. Fixes pymalloc fragmentation.\n2. `--max-memory-per-child 500000` (KB): Kill worker if memory exceeds 500Mi. Prevents leak-driven OOM.\n3. `--prefetch-multiplier 1`: Don't prefetch tasks. Prevents memory spike from deserializing queued tasks.\n\n**Right-sizing strategy:**\n- Measure per-task memory: max RSS during task execution\n- Memory request: master + (concurrency * per_task_P95)\n- Memory limit: master + (concurrency * per_task_Max) + 20% headroom\n- If tasks have variable memory: use `--max-memory-per-child` as safety net\n- Consider separate Deployments for memory-heavy vs lightweight tasks",
        "runtime-specific", p, runtime="python"))

    pairs.append(make_pair("runtime-mem-python-004",
        "Workload: deployment/ml-inference\nReplicas: 3\nContainer: python:3.11-slim\nCPU Request: 4000m, Limit: 8000m\nMemory Request: 8Gi, Limit: 16Gi\nCPU Usage (7d): P50=800m, P95=3500m, P99=5000m, Max=7500m\nMemory Usage (7d): P50=6Gi, P95=8Gi, P99=10Gi, Max=12Gi\nProcess model: gunicorn --workers 4, NumPy/PyTorch inference\nPattern: Burstable\nRestarts (7d): 0",
        "## Analysis\n\n**Memory**: 4 gunicorn workers, each loading a PyTorch model:\n- Per-worker base: ~500Mi (Python runtime + imported libraries)\n- Per-worker model: ~1Gi (loaded model weights in memory)\n- Per-worker inference peak: ~500Mi (intermediate tensors during forward pass)\n- Total per worker: ~2Gi peak\n- Total 4 workers: ~8Gi peak + master overhead\n- P50=6Gi: 2-3 workers actively processing, others idle\n- Max=12Gi: All 4 workers processing large batches simultaneously\n\n**CPU**: PyTorch uses OpenBLAS/MKL which release the GIL. 4 workers can collectively use more than 4 cores during matrix operations. This explains Max=7500m with 4 workers.\n\n## Recommendations\n\n**CPU**: Request=4200m (P95 * 1.20). Limit=8000m (keep — Max=7500m needs headroom).\n- Savings: Minimal on request (200m increase actually). Limit is appropriate.\n- Confidence: 0.80\n\n**Memory**: Request=9.6Gi (P95 * 1.20). Limit=15Gi (Max * 1.25).\n- Savings: 1Gi limit per pod = 3Gi total\n- Confidence: 0.75\n- Risk: MEDIUM — model size or batch size changes affect memory directly\n\n**Optimization suggestions:**\n1. Consider `OMP_NUM_THREADS=2` per worker (limits OpenBLAS threads). 4 workers * 2 threads = 8 threads total. Prevents thread over-subscription.\n2. If model is read-only: use `torch.multiprocessing` with `fork` start method. Workers share model memory pages via copy-on-write. Memory drops to ~1.2Gi per worker (shared model + per-worker inference buffers).\n3. With copy-on-write: Memory request drops to 4 * 1.2Gi + 500Mi = ~5.3Gi\n4. Consider model quantization (INT8) to halve model memory per worker.",
        "right-sizing", p, runtime="python", pattern="burstable"))

    pairs.append(make_pair("runtime-mem-python-005",
        "How does Python multiprocessing fork vs spawn affect container memory in Kubernetes?",
        "## Fork vs Spawn in Python Containers\n\n**Python multiprocessing has three start methods**, each with different K8s memory implications:\n\n**fork (Linux default):**\n- Child process shares parent's memory via copy-on-write (COW)\n- Initially: child uses ~0 extra memory (shared pages)\n- Over time: as child modifies objects, pages are copied. Memory grows.\n- Python GC issue: GC reference counting modifies every object's refcount. This triggers COW on almost all pages, negating the memory sharing benefit.\n- K8s result: Memory looks low at start, gradually increases to per-process levels\n- Risk: fork() with threads is unsafe (can deadlock). Many libraries create threads at import time.\n\n**spawn (macOS default, safest):**\n- Child process starts fresh Python interpreter and re-imports modules\n- No memory sharing with parent\n- K8s result: Immediate per-process memory from startup\n- Memory: `N_workers * full_process_memory` from the beginning\n- Startup: Slower (re-imports everything)\n\n**forkserver:**\n- Compromise: forks from a clean server process (no threads, minimal state)\n- Better than fork for thread safety\n- Memory: Similar to spawn for Python objects, but can share read-only data\n\n**Right-sizing by start method:**\n\n| Method | Initial memory | Peak memory | Right-size to |\n|--------|---------------|-------------|---------------|\n| fork | N * 200Mi | N * full_process | Peak (COW inflates over hours) |\n| spawn | N * full_process | N * full_process | Steady-state P95 |\n| forkserver | N * 300Mi | N * full_process | Peak (similar to fork) |\n\n**Recommendation**: Use `spawn` for predictable K8s memory. Use `fork` only if you understand COW implications and restart workers periodically to reset memory.\n\n**In K8s**: Set `PYTHONSTARTMETHOD=spawn` in env vars. For Celery: `--pool prefork` uses fork by default. Use `--max-tasks-per-child` to mitigate COW growth.",
        "runtime-specific", p, runtime="python"))

    return pairs


# ── Node.js Memory Model ────────────────────────────────────────────


def nodejs_memory_pairs() -> list[dict]:
    """Node.js V8 heap, --max-old-space-size, event loop, libuv."""
    p = "Expert knowledge: Node.js V8 runtime and container interactions"
    pairs = []

    pairs.append(make_pair("runtime-mem-node-001",
        "How does V8's memory model affect Node.js right-sizing in Kubernetes?",
        "## V8 Memory Model for K8s Right-Sizing\n\n**V8 (Node.js engine) has two main memory spaces:**\n\n1. **New Space (Young Generation):** 1-8MB. Short-lived objects. Scavenged frequently (fast GC).\n2. **Old Space (Old Generation):** Grows up to `--max-old-space-size`. Long-lived objects. Mark-sweep-compact GC (expensive).\n\n**Total V8 heap = New Space + Old Space + Code Space + Large Object Space**\n\n**Default limits (V8 auto-detects container memory since Node 12):**\n- If container limit is detected: ~75% of container limit\n- If no limit detected: ~1.5Gi on 64-bit systems\n- Override: `--max-old-space-size=2048` (MB)\n\n**Beyond V8 heap:**\n- Buffer pool: `Buffer.alloc()` allocates outside V8 heap (like JVM direct buffers)\n- Native addons: C++ memory allocations not tracked by V8\n- libuv thread pool: 4 threads default, each with stack + buffers (~10Mi total)\n- External strings: String data referenced from V8 but allocated externally\n\n**Container memory formula:**\n```\ncontainer_limit = max_old_space_size * 1.5 + 256Mi\n```\nThe 1.5x accounts for: new space, code space, GC overhead during compaction, external allocations, buffers.\n\n**Right-sizing Node.js:**\n- Memory request: RSS P95 * 1.20\n- Memory limit: max_old_space_size * 1.5 + 256Mi (or observed RSS Max * 1.25)\n- CPU request: Based on event loop utilization, not raw CPU metrics\n- Common mistake: Setting limit = max_old_space_size. Node WILL OOMKill during GC compaction.\n\n**Monitoring**: Use `process.memoryUsage()` — `heapUsed` (V8), `heapTotal` (V8 allocated), `rss` (total), `external` (C++ objects), `arrayBuffers` (Buffer pool).",
        "runtime-specific", p, runtime="node"))

    pairs.append(make_pair("runtime-mem-node-002",
        "How does Node.js --max-old-space-size interact with Kubernetes memory limits?",
        "## --max-old-space-size and K8s Limits\n\n**Since Node.js 12, V8 auto-detects container memory limits** (reads cgroup). But explicit `--max-old-space-size` overrides this detection.\n\n**Interactions:**\n\n| Node.js flag | Container limit | V8 heap max | Result |\n|-------------|----------------|------------|--------|\n| Not set | 2Gi | ~1.5Gi (75%) | Safe, auto-sized |\n| --max-old-space-size=4096 | 2Gi | 4Gi | OOMKill when heap > ~1.5Gi |\n| --max-old-space-size=1024 | 4Gi | 1Gi | Under-utilized, but safe |\n| Not set | No limit | ~1.5Gi | Wastes node memory if needs more |\n\n**Best practice:**\n1. Let V8 auto-size (don't set --max-old-space-size) when possible\n2. If setting explicitly: `--max-old-space-size = container_limit_MB * 0.65`\n3. The remaining 35% covers: GC overhead during compaction, Buffers, native allocations, libuv, kernel overhead\n\n**Container limit sizing from --max-old-space-size:**\n```\ncontainer_limit = max_old_space_size / 0.65\n```\nExample: --max-old-space-size=2048 → container limit = 3.15Gi → round to 3.5Gi\n\n**When to set it explicitly:**\n- Worker threads: Each worker gets its own V8 heap. Total = N * max_old_space_size\n- Known memory-intensive operations: Setting it lower triggers GC earlier, preventing OOM\n- Gradual memory growth: Lower limit forces earlier GC, trading CPU for memory stability\n\n**Node.js 20+ improvement**: `--max-semi-space-size` can also be tuned. Default 16MB for new space. For high-allocation-rate services (parsing JSON rapidly), increase to 64-128MB to reduce GC frequency.",
        "runtime-specific", p, runtime="node"))

    pairs.append(make_pair("runtime-mem-node-003",
        "How should I right-size CPU for Node.js workloads considering the event loop?",
        "## Node.js Event Loop and CPU Right-Sizing\n\n**Node.js is single-threaded for JavaScript execution.** The event loop processes I/O callbacks, timers, and microtasks on one core.\n\n**CPU components:**\n1. **Event loop (1 core max)**: JavaScript execution, JSON parsing, business logic\n2. **libuv thread pool (4 threads default)**: DNS resolution, file I/O, crypto, zlib\n3. **V8 GC threads (background)**: Concurrent mark-sweep uses ~2 threads\n4. **Worker threads (if used)**: Each has its own event loop and V8 instance\n\n**Total CPU capacity:**\n- Default Node.js: ~1 core (event loop) + 0.5 core (libuv+GC) = ~1.5 cores max\n- With `UV_THREADPOOL_SIZE=8`: ~1 + 1 = ~2 cores max\n- With 4 worker threads: ~5 cores max (1 main + 4 workers)\n\n**Right-sizing rules:**\n\n| Pattern | CPU request | CPU limit | Rationale |\n|---------|-----------|---------|----------|\n| I/O-bound API | 500m | 1500m | Event loop rarely saturated |\n| CPU-bound processing | 1000m | 2000m | Event loop + GC threads |\n| Worker threads (N=4) | 2000m | 5000m | N+1 cores for workers + main |\n| SSR (Next.js) | 1000m | 2000m | Render is CPU-bound on event loop |\n\n**Event loop lag as a metric:**\n```javascript\nconst lag = performance.eventLoopUtilization();\n// If utilization > 0.7, event loop is saturated\n// CPU request should be increased or add replicas via HPA\n```\n\n**Common mistake**: Setting CPU limit to 8000m for a standard Node.js app. A single-process Node.js app physically cannot use more than ~2000m. The extra limit is wasted and misleads capacity planning.\n\n**Recommendation**: For standard Node.js (no worker threads), CPU limit 1500-2000m. Use HPA on event loop utilization (custom metric) to scale replicas instead of vertical scaling.",
        "runtime-specific", p, runtime="node"))

    pairs.append(make_pair("runtime-mem-node-004",
        "Workload: deployment/bff-service\nRuntime: Node.js 20\nReplicas: 4\nCPU Request: 2000m, Limit: 4000m\nMemory Request: 2Gi, Limit: 4Gi\nCPU Usage (7d): P50=300m, P95=700m, P99=900m, Max=1200m\nMemory Usage (7d): P50=800Mi, P95=1.1Gi, P99=1.3Gi, Max=1.5Gi\nFlags: --max-old-space-size=2048\nEvent loop utilization (avg): 0.35\nPattern: Steady\nRestarts (7d): 0",
        "## Analysis\n\n**Memory**: --max-old-space-size=2048 (2Gi), container limit=4Gi.\n- V8 heap using ~800Mi-1.5Gi of the 2Gi old space budget\n- Non-heap: ~200-300Mi (Buffers, libuv, native)\n- Container has 2.5Gi unused headroom above Max\n- The 4Gi limit is 2x what's needed\n\n**CPU**: Event loop utilization at 0.35 means the event loop is idle 65% of the time. Max CPU 1200m includes libuv thread pool and GC. This workload is far from CPU-bound.\n\n**CPU limit of 4000m is 3.3x the Max**. A single-process Node.js app cannot use 4 cores.\n\n## Recommendations\n\n**Memory**: Request=1.32Gi (P95 * 1.20). Limit=2Gi (Max * 1.33 or max_old_space_size * 1.0).\n- Reduce --max-old-space-size to 1200 (MB) since heap peak is ~1.3Gi\n- New limit: 1200 * 1.5 + 256Mi ≈ 2Gi\n- Savings: 680Mi request + 2Gi limit per pod = 2.72Gi + 8Gi total\n- Confidence: 0.90\n\n**CPU**: Request=840m (P95 * 1.20). Limit=1500m (Max * 1.25, capped at Node.js physical max).\n- Savings: 1160m request + 2500m limit per pod\n- Confidence: 0.90\n- Risk: LOW -- event loop utilization 0.35 confirms plenty of headroom\n\n**Optimization**: With 4 replicas at 35% event loop utilization, the service is over-replicated. Consider reducing to 3 replicas with HPA scaling on event loop utilization > 0.6.\n- Total savings with 3 replicas: ~25% on all resources",
        "right-sizing", p, runtime="node", pattern="steady"))

    pairs.append(make_pair("runtime-mem-node-005",
        "How do Node.js worker threads affect container resource right-sizing?",
        "## Worker Threads and K8s Right-Sizing\n\n**Worker threads (Node.js 12+) create additional V8 instances** within the same process. Each worker has its own event loop, GC, and heap.\n\n**Memory impact:**\n- Each worker thread gets its own `--max-old-space-size` allocation\n- `SharedArrayBuffer` allows zero-copy data sharing between workers\n- Without sharing: total memory = (1 + N_workers) * per_worker_heap + shared_overhead\n\n**CPU impact:**\n- Each worker can saturate 1 core (its own event loop)\n- CPU limit should be >= (1 + N_workers) * 1000m for CPU-bound workers\n- I/O-bound workers: (1 + N_workers) * 500m typically sufficient\n\n**Example: Image processing service with 4 worker threads**\n```\nMemory:\n- Main thread heap: 512Mi (routing, task distribution)\n- Per worker heap: 1Gi (image data, processing buffers)\n- Total V8: 512Mi + 4 * 1Gi = 4.5Gi\n- Non-heap: 500Mi (native image codecs, Buffers)\n- Container limit: 6Gi\n- Container request: P95 of observed RSS\n\nCPU:\n- Main thread: ~200m (task routing)\n- Per worker during processing: ~950m (image manipulation)\n- Idle workers: ~50m each\n- Peak CPU: 200m + 4 * 950m = 4Gi\n- Container limit: 5000m\n- Container request: P95 observed\n```\n\n**Right-sizing strategy:**\n1. Set `--max-old-space-size` per worker via `workerData` or `WORKER_MAX_OLD_SPACE_SIZE` env\n2. Total container limit = sum of all max_old_space_sizes * 1.4 + 512Mi\n3. CPU limit = (1 + N_workers) * 1100m (1 core + 10% GC overhead per worker)\n4. Monitor per-worker heap usage to identify workers that need different sizing\n\n**Anti-pattern**: Using worker_threads for I/O-bound work. Workers are for CPU-intensive tasks. For I/O concurrency, use async/await on the main event loop. Unnecessary workers waste memory (each V8 instance = 50-100Mi minimum).",
        "runtime-specific", p, runtime="node"))

    return pairs


# ── .NET Memory Model ───────────────────────────────────────────────


def dotnet_memory_pairs() -> list[dict]:
    """.NET GC modes, GCHeapHardLimit, container awareness."""
    p = "Expert knowledge: .NET runtime memory model and container interactions"
    pairs = []

    pairs.append(make_pair("runtime-mem-dotnet-001",
        "How does .NET garbage collection affect container right-sizing in Kubernetes?",
        "## .NET GC Modes for K8s\n\n**.NET has two GC modes with dramatically different resource profiles:**\n\n**Server GC (default for ASP.NET Core):**\n- Creates one GC heap per logical processor\n- On a 16-core node with 2000m CPU limit: 16 GC heaps (reads host cores, not cgroup)\n- Each heap has its own memory segments\n- Memory usage: 16 heaps * min_segment_size = high baseline\n- GC throughput: High (parallel collection across heaps)\n- Latency: Higher pause times (more heaps to collect)\n\n**Workstation GC:**\n- Single GC heap regardless of core count\n- Memory usage: Minimal baseline (~50-100Mi for GC)\n- GC throughput: Lower but consistent\n- Latency: Lower pause times\n\n**K8s problem**: Server GC reads `/proc/cpuinfo` (host cores) not cgroup CPU limit. On a 64-core node with 1000m limit:\n- 64 GC heaps created, each consuming memory\n- Memory overhead: ~500Mi just for GC infrastructure\n- GC threads compete for 1000m CPU, causing throttling\n\n**Fix (.NET 8+):** .NET 8 is fully container-aware. For older versions:\n```dockerfile\nENV DOTNET_PROCESSOR_COUNT=2  # Match your CPU limit\nENV DOTNET_GCServer=0          # Use Workstation GC for small containers\n```\n\n**Right-sizing by GC mode:**\n\n| Container CPU limit | Recommended GC | PROCESSOR_COUNT |\n|--------------------|----------------|------------------|\n| < 1000m | Workstation | 1 |\n| 1000m - 2000m | Workstation or Server | 2 |\n| 2000m - 4000m | Server | CPU_limit/1000 |\n| > 4000m | Server | CPU_limit/1000 |\n\n**Memory formula (Server GC):**\n```\ncontainer_limit = working_set + (PROCESSOR_COUNT * 64Mi) + 256Mi\n```",
        "runtime-specific", p, runtime="dotnet"))

    pairs.append(make_pair("runtime-mem-dotnet-002",
        "How does GCHeapHardLimit work in .NET containers and how should I configure it?",
        "## GCHeapHardLimit for .NET in K8s\n\n**GCHeapHardLimit sets a hard ceiling on GC heap size.** .NET 8+ automatically sets this to 75% of container memory limit.\n\n**Configuration:**\n```csharp\n// In runtimeconfig.json\n{ \"configProperties\": { \"System.GC.HeapHardLimit\": 1073741824 } }  // 1Gi in bytes\n\n// Or via environment variable\nENV DOTNET_GCHeapHardLimit=0x40000000  // Hex, 1Gi\n\n// .NET 8+: percentage-based (recommended)\nENV DOTNET_GCHeapHardLimitPercent=0x4B  // 75% (0x4B = 75)\n```\n\n**How it works:**\n1. GC heap cannot grow beyond the limit\n2. When approaching limit, GC becomes progressively more aggressive\n3. If limit is reached, GC runs full blocking collection\n4. If still exceeded: `OutOfMemoryException` (managed exception, not kernel OOMKill)\n\n**K8s interaction:**\n- Without GCHeapHardLimit: .NET GC may grow heap beyond container limit → OOMKill\n- With GCHeapHardLimit: .NET throws managed exception → catchable, loggable\n- .NET 8+ auto-sets to 75% of cgroup limit → safe by default\n\n**Right-sizing with GCHeapHardLimit:**\n\n| Setting | Container limit | GC heap max | Non-GC budget | Notes |\n|---------|----------------|------------|---------------|---------|\n| Auto (.NET 8) | 2Gi | 1.5Gi (75%) | 512Mi | Safe default |\n| 60% | 2Gi | 1.2Gi | 800Mi | Better for native interop |\n| 80% | 2Gi | 1.6Gi | 400Mi | Tight, only for pure .NET |\n\n**Non-GC memory includes:** Thread stacks, native allocations, memory-mapped files, gRPC buffers, Kestrel connection buffers.\n\n**Recommendation**: Use .NET 8+ auto-detection. Set `GCHeapHardLimitPercent=65` if your app uses native libraries (gRPC, image processing, crypto). Monitor `dotnet_gc_heap_size_bytes` (Prometheus) vs container RSS to validate the split.",
        "runtime-specific", p, runtime="dotnet"))

    pairs.append(make_pair("runtime-mem-dotnet-003",
        "Workload: deployment/catalog-api\nRuntime: .NET 8 (ASP.NET Core)\nReplicas: 3\nCPU Request: 2000m, Limit: 4000m\nMemory Request: 4Gi, Limit: 8Gi\nCPU Usage (7d): P50=400m, P95=1200m, P99=1800m, Max=2500m\nMemory Usage (7d): P50=1.8Gi, P95=2.5Gi, P99=3.0Gi, Max=3.5Gi\nGC Mode: Server GC, DOTNET_PROCESSOR_COUNT not set\nNode cores: 32\nPattern: Steady\nRestarts (7d): 0",
        "## Analysis\n\n**Critical issue**: Server GC on a 32-core node without DOTNET_PROCESSOR_COUNT. .NET created 32 GC heaps, each with managed heap segments.\n\n**Memory breakdown:**\n- GC infrastructure: 32 heaps * ~20Mi each = ~640Mi overhead (could be ~40Mi with 2 heaps)\n- Application working set: ~1.2Gi (actual live objects)\n- Thread pool: .NET creates threads proportional to PROCESSOR_COUNT. 32 ThreadPool threads at startup.\n- P50=1.8Gi is higher than expected for an API because of the 32-heap overhead.\n\n**CPU**: P95=1200m on steady pattern. The 32-core detection means .NET's ThreadPool tries to maintain 32 threads, causing unnecessary context switching within the 2000m limit.\n\n## Recommendations\n\n**Immediate fix**: Set `DOTNET_PROCESSOR_COUNT=2` (matching CPU limit / 1000)\n- Expected memory reduction: ~500Mi (fewer GC heaps)\n- Expected CPU reduction: ~15% (less thread contention)\n\n**After fix, re-measure for 7d. Expected new metrics:**\n- Memory P95: ~2.0Gi (from 2.5Gi)\n- CPU P95: ~1000m (from 1200m)\n\n**Then right-size:**\n- Memory: Request=2.4Gi (expected P95 * 1.20). Limit=4Gi.\n- CPU: Request=1200m (expected P95 * 1.20). Limit=3125m (Max * 1.25).\n- Savings: ~1.6Gi request + 4Gi limit per pod; ~800m request + 875m limit per pod\n- Total across 3 replicas: 4.8Gi + 12Gi memory; 2400m + 2625m CPU\n- Confidence: 0.80 (need to re-measure after PROCESSOR_COUNT fix)\n\n**Also consider**: For a 2000m CPU limit, Workstation GC may perform better. Lower memory overhead, lower GC pause times. Test with `DOTNET_GCServer=0`.",
        "right-sizing", p, runtime="dotnet", pattern="steady"))

    pairs.append(make_pair("runtime-mem-dotnet-004",
        "What are the key differences between .NET 6 and .NET 8 for container right-sizing?",
        "## .NET 6 vs .NET 8 Container Awareness\n\n**.NET 8 significantly improved container-aware resource management.**\n\n| Feature | .NET 6 | .NET 8 |\n|---------|--------|--------|\n| Cgroup v2 support | Partial | Full |\n| Auto GCHeapHardLimit | No | Yes (75% of limit) |\n| Auto PROCESSOR_COUNT | Reads cpuset, not quota | Reads CPU quota correctly |\n| Dynamic adaptation | No | GC adapts to memory pressure |\n| Container metrics API | Basic | Full (via Meter API) |\n\n**Right-sizing differences:**\n\n**.NET 6 containers require explicit configuration:**\n```yaml\nenv:\n- name: DOTNET_PROCESSOR_COUNT\n  value: \"2\"                    # Must set manually\n- name: DOTNET_GCHeapHardLimit\n  value: \"0x60000000\"           # 1.5Gi, must calculate manually\n- name: COMPlus_GCServer\n  value: \"0\"                    # May need Workstation GC\n```\n\n**.NET 8 containers work correctly with minimal config:**\n```yaml\n# Just set appropriate resource limits - .NET 8 auto-configures\nresources:\n  requests:\n    cpu: \"1000m\"\n    memory: \"2Gi\"\n  limits:\n    cpu: \"2000m\"\n    memory: \"4Gi\"\n# .NET 8 will:\n# - Set PROCESSOR_COUNT = 2 (from CPU limit)\n# - Set GCHeapHardLimit = 3Gi (75% of 4Gi)\n# - Choose appropriate GC mode\n```\n\n**Migration impact on right-sizing:**\nWhen upgrading .NET 6 → .NET 8:\n1. Remove explicit PROCESSOR_COUNT (let .NET detect)\n2. Remove GCHeapHardLimit (let .NET auto-set)\n3. Re-measure for 7d — memory and CPU profiles will change\n4. Memory typically drops 10-20% (better GC heap management)\n5. CPU may increase slightly (more accurate thread pool, less idle spinning)\n6. Re-right-size after stabilisation\n\n**If staying on .NET 6**: Always set PROCESSOR_COUNT and consider GCHeapHardLimit. Without these, .NET 6 will overcommit on multi-core nodes.",
        "runtime-specific", p, runtime="dotnet"))

    return pairs


# ── Rust Memory Model ───────────────────────────────────────────────


def rust_memory_pairs() -> list[dict]:
    """Rust: no GC, jemalloc/mimalloc, RSS vs virtual."""
    p = "Expert knowledge: Rust runtime memory model and container interactions"
    pairs = []

    pairs.append(make_pair("runtime-mem-rust-001",
        "How does Rust's lack of garbage collector affect Kubernetes right-sizing?",
        "## Rust Memory Model for K8s Right-Sizing\n\n**Rust has no garbage collector.** Memory is managed at compile time through ownership and borrowing. This makes Rust the most predictable runtime for K8s right-sizing.\n\n**Characteristics:**\n1. **No GC pauses**: CPU usage is smooth. No spikes from stop-the-world collection.\n2. **No GC overhead**: No extra memory for GC metadata, remembered sets, or card tables. Container memory = actual application memory.\n3. **Deterministic deallocation**: Memory is freed when the owning variable goes out of scope. No delay.\n4. **RSS closely tracks actual usage**: No retained-but-reclaimable pages (unlike Go, JVM).\n\n**Memory breakdown for a Rust service:**\n- Binary + shared libraries: 10-50Mi (statically linked = smaller)\n- Stack: 8MB per thread (default), configurable\n- Heap: Application data, dynamically allocated\n- mmap regions: If using memory-mapped I/O\n\n**Right-sizing Rust:**\n- Memory request = P95 RSS * 1.15 (tighter headroom than GC languages)\n- Memory limit = Max RSS * 1.20\n- CPU request = P95 * 1.15\n- CPU limit = Max * 1.20 (or remove limit for burstable)\n- Headroom can be smaller because there are no GC spikes\n\n**Comparison (same workload, different runtimes):**\n\n| Runtime | Base memory | GC overhead | Total for 500Mi live data | Right-size limit |\n|---------|------------|------------|--------------------------|------------------|\n| Rust | 20Mi | 0 | 520Mi | 650Mi |\n| Go | 50Mi | 100% (GOGC) | 1050Mi | 1.3Gi |\n| JVM (G1) | 200Mi | 15% heap + metaspace | 1.1Gi | 1.4Gi |\n| Python | 100Mi | refcount + pymalloc | 800Mi | 1Gi |\n\n**When Rust memory is unpredictable:**\n- Using jemalloc (caches freed memory in thread-local caches)\n- Unsafe code with manual memory management\n- FFI calls to C libraries (C allocations not tracked by Rust)",
        "runtime-specific", p, runtime="rust"))

    pairs.append(make_pair("runtime-mem-rust-002",
        "How do jemalloc and mimalloc affect Rust container memory in Kubernetes?",
        "## Allocator Choice for Rust in K8s\n\n**Rust's default allocator is the system allocator (glibc malloc on Linux).** Many projects switch to jemalloc or mimalloc for performance.\n\n**System allocator (glibc malloc):**\n- Memory: Returns memory to OS relatively quickly\n- RSS tracks actual usage closely\n- Fragmentation: Moderate, can cause RSS growth over time\n- K8s: Most predictable for right-sizing\n\n**jemalloc:**\n- Memory: Retains freed memory in thread caches (tcaches) and arenas\n- RSS stays elevated after usage spikes (similar to Go behaviour)\n- Throughput: 10-30% faster allocation for multi-threaded workloads\n- K8s: RSS overstates actual memory need. Use `jemalloc.stats.resident` for true usage\n- Configure: `MALLOC_CONF=background_thread:true,dirty_decay_ms:5000` to release memory faster\n\n**mimalloc:**\n- Memory: Uses per-thread heaps with segment caching\n- RSS: 5-15% higher than glibc but more consistent (less fragmentation)\n- Throughput: 15-40% faster for allocation-heavy workloads\n- K8s: Slightly inflated RSS but stable over time\n\n**Right-sizing by allocator:**\n\n| Allocator | Memory headroom | RSS behaviour | Tuning env vars |\n|-----------|----------------|--------------|------------------|\n| glibc | +15% | Tracks usage | MALLOC_TRIM_THRESHOLD_ |\n| jemalloc | +25% | Retains after spike | MALLOC_CONF dirty_decay_ms |\n| mimalloc | +20% | Stable, slightly high | MIMALLOC_ARENA_EAGER_COMMIT |\n\n**Recommendation for K8s:**\n- If memory efficiency matters: Use glibc or jemalloc with `dirty_decay_ms:1000`\n- If allocation throughput matters: Use mimalloc, accept 15% RSS overhead\n- Always base right-sizing on observed RSS, not theoretical. Each allocator has different retention behaviour.",
        "runtime-specific", p, runtime="rust"))

    pairs.append(make_pair("runtime-mem-rust-003",
        "Workload: deployment/edge-proxy\nRuntime: Rust (tokio async runtime)\nReplicas: 4\nCPU Request: 1000m, Limit: 2000m\nMemory Request: 1Gi, Limit: 2Gi\nCPU Usage (7d): P50=150m, P95=500m, P99=700m, Max=1000m\nMemory Usage (7d): P50=120Mi, P95=180Mi, P99=220Mi, Max=280Mi\nAllocator: jemalloc\nAsync tasks (avg): 15,000 concurrent\nPattern: Steady\nRestarts (7d): 0",
        "## Analysis\n\n**Memory**: 280Mi max for 15,000 concurrent connections is extremely efficient. Breakdown:\n- Binary + libs: ~15Mi (statically linked Rust)\n- Tokio runtime: ~10Mi (task scheduler, reactor)\n- Per-connection state: 15,000 * ~15KB = ~220Mi (buffers, TLS state, connection metadata)\n- jemalloc overhead: ~30Mi (thread caches)\n\nThe 2Gi limit is 7x the Max. Massively over-provisioned.\n\n**CPU**: Tokio async runtime on a Rust proxy is very CPU-efficient. P95=500m handling 15K connections. The 2000m limit is 2x the Max.\n\n## Recommendations\n\n**Memory**: Request=216Mi (P95 * 1.20). Limit=400Mi (Max * 1.43, generous for connection spikes).\n- Savings: 808Mi request + 1.6Gi limit per pod = 3.2Gi + 6.4Gi total\n- Confidence: 0.90\n- Risk: LOW -- Rust memory is deterministic. Connection spikes scale linearly.\n\n**CPU**: Request=600m (P95 * 1.20). Limit=1250m (Max * 1.25).\n- Savings: 400m request + 750m limit per pod = 1.6Gi + 3Gi total\n- Confidence: 0.90\n\n**Note on Rust efficiency**: This workload demonstrates why Rust services often over-provision by 5-10x. Operations teams accustomed to JVM/Python defaults set 1-2Gi for all services. Rust services rarely need more than 256-512Mi for typical API/proxy workloads.\n\n**jemalloc tuning**: With `MALLOC_CONF=dirty_decay_ms:1000`, jemalloc releases unused pages faster. May reduce P50 from 120Mi to ~100Mi. Minor impact on a workload this small.",
        "right-sizing", p, runtime="rust", pattern="steady"))

    return pairs


# ── Cross-Runtime ────────────────────────────────────────────────────


def cross_runtime_pairs() -> list[dict]:
    """Cross-runtime comparison and selection guidance."""
    p = "Expert knowledge: cross-runtime resource comparison for Kubernetes"
    pairs = []

    pairs.append(make_pair("runtime-mem-cross-001",
        "How do I choose the right headroom percentages for different runtimes when right-sizing in Kubernetes?",
        "## Runtime-Specific Headroom Guide\n\n**Different runtimes need different headroom** because of their memory management characteristics.\n\n| Runtime | Memory headroom (request) | Memory headroom (limit) | CPU headroom | Rationale |\n|---------|--------------------------|------------------------|-------------|----------|\n| Rust | 15% over P95 | 20% over Max | 15% | No GC, deterministic |\n| Go | 20% over P95 working_set | 30% over Max RSS | 20% | GOGC overhead, RSS retention |\n| Node.js | 20% over P95 | 50% over max_old_space | 20% | GC compaction, Buffers |\n| JVM (G1) | 25% over P95 | 50% over Xmx | 25% | Off-heap, metaspace, GC overhead |\n| JVM (ZGC) | 20% over P95 | 40% over Xmx | 20% | Lower GC overhead, but multi-mapping |\n| Python | 25% over P95 | 30% over Max | 15% | Fragmentation, but GIL limits CPU |\n| .NET | 20% over P95 | 35% over Max | 20% | Server GC heap overhead |\n\n**Why the differences:**\n\n1. **GC languages need more limit headroom**: GC runs need temporary memory for object copying/compaction. JVM G1GC can temporarily use 2x live set during full GC.\n\n2. **Languages with RSS retention need higher request-to-limit ratio**: Go and JVM keep freed pages mapped. Working set may be 50% of RSS. Set request based on working_set, limit based on RSS.\n\n3. **Single-threaded runtimes need less CPU headroom**: Python (GIL) and Node.js (event loop) have a natural ceiling. Extra CPU headroom is wasted.\n\n4. **Rust is the tightest**: No GC, no RSS retention, no runtime overhead. 15-20% headroom handles kernel overhead and minor allocation spikes.\n\n**Universal rules (all runtimes):**\n- Never set memory limit < observed Max (any runtime will OOMKill)\n- Never set CPU request < P50 (guaranteed baseline must cover normal operation)\n- Always use 7d of data minimum for reliable percentiles\n- Safety floors: 50m CPU, 64Mi memory (regardless of runtime)",
        "right-sizing", p, runtime="generic"))

    pairs.append(make_pair("runtime-mem-cross-002",
        "How do I interpret container_memory_rss vs container_memory_working_set_bytes for different runtimes?",
        "## RSS vs Working Set by Runtime\n\n**These two metrics mean different things depending on the runtime:**\n\n```\nRSS = all pages mapped to physical memory (including reclaimable)\nWorking Set = pages actively in use (RSS - inactive file-backed pages)\n```\n\n**Per-runtime interpretation:**\n\n**JVM (G1/ZGC):**\n- RSS ≈ Working Set (Java heap is actively used, not file-backed)\n- Exception: ZGC multi-maps heap pages → RSS appears 2-3x actual physical usage\n- For ZGC: use `jvm_memory_bytes_used` Prometheus metric, not container RSS\n- Right-size to: RSS P95 for G1, Working Set P95 for ZGC\n\n**Go:**\n- RSS >> Working Set (Go retains freed pages with MADV_FREE)\n- RSS/Working Set ratio: typically 1.5-3x\n- Working Set is the truth for Go. RSS includes memory the kernel CAN reclaim.\n- Right-size to: Working Set P95 for request, RSS Max for limit\n\n**Python:**\n- RSS ≈ Working Set (pymalloc arenas are actively tracked)\n- RSS grows monotonically due to fragmentation\n- Both metrics ratchet up over time\n- Right-size to: RSS P95 (working set doesn't help for Python)\n\n**Node.js:**\n- RSS ≈ Working Set + Buffer pool\n- Buffer pool memory may show in RSS but not working set\n- Right-size to: RSS P95 for request, RSS Max * 1.25 for limit\n\n**Rust:**\n- RSS ≈ Working Set (no GC, minimal overhead)\n- With jemalloc: RSS slightly > Working Set (thread caches)\n- Right-size to: RSS P95 (most accurate metric for Rust)\n\n**.NET:**\n- RSS ≈ Working Set in most cases\n- Server GC: RSS includes GC heap segments (may be partially empty)\n- Right-size to: Working Set P95 for request\n\n**General rule**: When RSS and Working Set diverge by more than 50%, the runtime is retaining reclaimable memory. Use Working Set for request (scheduler guarantee) and RSS for limit (hard ceiling).",
        "runtime-specific", p, runtime="generic"))

    pairs.append(make_pair("runtime-mem-cross-003",
        "Our team is choosing between Go, Rust, and Java for a new Kubernetes microservice. What are the resource implications for right-sizing?",
        "## Runtime Selection: Resource Implications for K8s\n\n**For an equivalent microservice (REST API, 1000 req/s, 100ms P99 latency target):**\n\n| Aspect | Go | Rust | Java (Spring Boot) |\n|--------|-----|------|--------------------|\n| Base memory (idle) | 30-50Mi | 10-20Mi | 200-400Mi |\n| Memory at 1K rps | 100-200Mi | 50-100Mi | 500Mi-1Gi |\n| CPU at 1K rps | 200-400m | 100-300m | 300-600m |\n| Startup time | <1s | <1s | 5-15s (Spring) |\n| Container limit | 512Mi | 256Mi | 1.5Gi |\n| GC impact | Moderate (GOGC) | None | Significant (G1/ZGC) |\n| Right-sizing complexity | Medium | Low | High |\n\n**Cost at scale (100 replicas, 7d):**\n\n| Runtime | Total CPU request | Total Memory request | Relative cost |\n|---------|------------------|---------------------|---------------|\n| Go | 40,000m | 20Gi | 1.0x |\n| Rust | 25,000m | 10Gi | 0.6x |\n| Java | 60,000m | 80Gi | 2.5x |\n\n**When to choose each:**\n\n**Go**: Best balance of development speed and resource efficiency. Excellent for microservices, CLI tools, infrastructure components. Good K8s integration (client-go). Right-sizing is straightforward with GOMEMLIMIT.\n\n**Rust**: Lowest resource footprint. Choose when running at extreme scale (1000+ replicas) where per-pod savings multiply. Or for latency-critical services (no GC pauses). Higher development cost.\n\n**Java**: Choose when leveraging existing Java expertise, Spring ecosystem, or JVM libraries. Accept higher resource cost. Right-sizing is complex due to off-heap, GC modes, and container awareness gaps in older JDKs.\n\n**k8s-sage recommendation**: The runtime choice matters less than proper right-sizing. A well-right-sized Java service costs less than an over-provisioned Rust service. Focus on measurement and adjustment, not runtime selection.",
        "runtime-specific", p, runtime="generic"))

    pairs.append(make_pair("runtime-mem-cross-004",
        "How should I right-size a multi-runtime pod that has a Go sidecar, a JVM main container, and a Python init container?",
        "## Multi-Runtime Pod Right-Sizing\n\n**Each container in the pod uses a different runtime with different memory/CPU characteristics. Size each independently.**\n\n**Init container (Python):**\n- Runs once at startup, then terminates\n- Memory/CPU usage counts during startup only\n- Set resources for peak startup need\n- After completion, resources are released (but init container limits affect pod QoS calculation)\n- Typical: 256Mi memory, 500m CPU for a data migration or config generation script\n\n**Main container (JVM):**\n- Apply JVM right-sizing rules: account for Xmx, metaspace, off-heap\n- Container limit = Xmx * 1.5 + 512Mi\n- CPU: Account for GC threads + application threads\n- This dominates the pod's resource budget\n\n**Sidecar (Go — e.g., Envoy proxy, log shipper):**\n- Apply Go right-sizing: use working_set, not RSS\n- Typically low resource: 100-200Mi memory, 100-300m CPU\n- IMPORTANT: Sidecar resources are often overlooked. An Envoy sidecar can use 500Mi+ under load.\n\n**Pod total:**\n```yaml\ninitContainers:\n- name: data-init\n  resources:\n    requests: { cpu: 500m, memory: 256Mi }\n    limits:   { cpu: 1000m, memory: 512Mi }\ncontainers:\n- name: app  # JVM\n  resources:\n    requests: { cpu: 2000m, memory: 4Gi }   # Based on JVM right-sizing\n    limits:   { cpu: 4000m, memory: 6Gi }\n- name: proxy  # Go sidecar\n  resources:\n    requests: { cpu: 100m, memory: 128Mi }  # Based on Go right-sizing\n    limits:   { cpu: 500m, memory: 256Mi }\n```\n\n**Pod scheduling**: Scheduler uses sum of container requests. Pod request = 2100m CPU, 4.1Gi memory. Init container resources don't add (max of init vs sum of regular containers).\n\n**Key insight**: The sidecar's P99 CPU spike may coincide with the main container's spike (both handling the same request). Size for concurrent peaks, not independent averages.",
        "right-sizing", p, runtime="generic"))

    pairs.append(make_pair("runtime-mem-cross-005",
        "How do container runtime metrics differ between cgroups v1 and v2 and how does this affect right-sizing across runtimes?",
        "## cgroups v1 vs v2 Metric Accuracy by Runtime\n\n**cgroups v2 provides more accurate container metrics**, but some runtimes interact differently with each version.\n\n**Key metric differences:**\n\n| Metric | cgroups v1 | cgroups v2 | Impact |\n|--------|-----------|-----------|--------|\n| Memory usage | `memory.usage_in_bytes` (includes kernel cache) | `memory.current` (includes kernel cache) | v1 can overcount |\n| Memory working set | RSS only | RSS + shmem - inactive file | v2 more accurate |\n| Memory pressure | Not available | `memory.pressure` (PSI) | v2 enables proactive right-sizing |\n| CPU usage | `cpuacct.usage` | `cpu.stat usage_usec` | Equivalent |\n| CPU throttling | `cpu.stat nr_throttled` | `cpu.stat nr_throttled` | Same, but v2 more reliable |\n\n**Per-runtime cgroups impact:**\n\n**JVM**: On cgroups v1, older JDKs (< 11) don't detect container limits. On v2, JDK 15+ auto-detects. Always verify with `-XshowSettings:system`.\n\n**Go**: Go 1.19+ reads cgroups v2 for GOMEMLIMIT auto-detection. On v1, `automaxprocs` reads `cpu.cfs_quota_us/cpu.cfs_period_us`. Both work but v2 paths are cleaner.\n\n**Node.js**: V8 reads container memory limit from cgroups to auto-size heap. Works on both v1 and v2 since Node 12.\n\n**.NET**: .NET 8 fully supports cgroups v2. .NET 6 has partial support — verify PROCESSOR_COUNT detection.\n\n**Python**: Python itself doesn't read cgroups. Libraries like `resource` module read system-level limits.\n\n**Right-sizing implications:**\n- On cgroups v1: `container_memory_usage_bytes` may be inflated by kernel page cache. Use `container_memory_working_set_bytes` for right-sizing.\n- On cgroups v2: `memory.current` still includes some cache. Use `container_memory_working_set_bytes` (Kubelet-calculated) for consistency.\n- PSI (v2 only): If `memory.pressure` shows stalls > 0, the container is memory-constrained even if not OOMKilling. Increase memory request.\n\n**Verify your cluster**: `stat /sys/fs/cgroup/cgroup.controllers` — exists on v2, doesn't on v1.",
        "runtime-specific", p, runtime="generic"))

    return pairs


# ── Main ─────────────────────────────────────────────────────────────


def generate_all() -> list[dict]:
    """Collect all runtime memory pairs."""
    all_pairs = []
    all_pairs.extend(jvm_memory_pairs())
    all_pairs.extend(go_memory_pairs())
    all_pairs.extend(python_memory_pairs())
    all_pairs.extend(nodejs_memory_pairs())
    all_pairs.extend(dotnet_memory_pairs())
    all_pairs.extend(rust_memory_pairs())
    all_pairs.extend(cross_runtime_pairs())

    # Validate
    ids = set()
    for pair in all_pairs:
        pid = pair["id"]
        assert pid not in ids, f"Duplicate ID: {pid}"
        ids.add(pid)
        assert len(pair["assistant"]) >= 50, f"{pid}: assistant too short"
        assert pair["metadata"]["category"] in (
            "right-sizing", "classification", "runtime-specific", "edge-case"
        ), f"{pid}: bad category"
        assert pair["metadata"].get("provenance"), f"{pid}: missing provenance"

    # Write
    OUTPUT_PATH.parent.mkdir(parents=True, exist_ok=True)
    with open(OUTPUT_PATH, "w") as f:
        for pair in all_pairs:
            f.write(json.dumps(pair) + "\n")

    print(f"Wrote {len(all_pairs)} runtime memory pairs -> {OUTPUT_PATH}")
    return all_pairs


if __name__ == "__main__":
    pairs = generate_all()
    cats = {}
    runtimes = {}
    for p in pairs:
        c = p["metadata"]["category"]
        cats[c] = cats.get(c, 0) + 1
        r = p["metadata"].get("runtime", "none")
        runtimes[r] = runtimes.get(r, 0) + 1
    print("Pairs by category:")
    for cat, count in sorted(cats.items()):
        print(f"  {cat}: {count}")
    print("Pairs by runtime:")
    for rt, count in sorted(runtimes.items()):
        print(f"  {rt}: {count}")
